const STORAGE_PREFIX = 'pkr:dismissed-eliminated-tournaments:';
const CHANGE_EVENT = 'pkr:dismissed-eliminated-tournaments-change';

type DismissedTournamentChange = {
  userId: string;
  tournamentIds: number[];
};

function storageKey(userId: string) {
  return `${STORAGE_PREFIX}${userId}`;
}

function readDismissedSet(userId: string) {
  if (typeof window === 'undefined') return new Set<number>();

  try {
    const rawValue = window.localStorage.getItem(storageKey(userId));
    const parsed = rawValue ? JSON.parse(rawValue) : [];
    if (!Array.isArray(parsed)) return new Set<number>();

    return new Set(
      parsed
        .map(value => Number(value))
        .filter(value => Number.isFinite(value)),
    );
  } catch {
    return new Set<number>();
  }
}

function writeDismissedSet(userId: string, tournamentIds: Set<number>) {
  if (typeof window === 'undefined') return;

  const next = Array.from(tournamentIds).sort((left, right) => left - right);
  window.localStorage.setItem(storageKey(userId), JSON.stringify(next));
  window.dispatchEvent(new CustomEvent<DismissedTournamentChange>(CHANGE_EVENT, {
    detail: {
      userId,
      tournamentIds: next,
    },
  }));
}

export function getDismissedEliminatedTournaments(userId: string) {
  return readDismissedSet(userId);
}

export function isEliminatedTournamentDismissed(userId: string | null | undefined, tournamentId: number | null | undefined) {
  if (!userId || typeof tournamentId !== 'number' || !Number.isFinite(tournamentId)) return false;
  return readDismissedSet(userId).has(tournamentId);
}

export function dismissEliminatedTournament(userId: string, tournamentId: number) {
  if (!Number.isFinite(tournamentId)) return;

  const dismissed = readDismissedSet(userId);
  if (dismissed.has(tournamentId)) return;

  dismissed.add(tournamentId);
  writeDismissedSet(userId, dismissed);
}

export function watchDismissedEliminatedTournaments(
  userId: string,
  listener: (tournamentIds: Set<number>) => void,
) {
  listener(readDismissedSet(userId));

  const notify = () => listener(readDismissedSet(userId));

  const onStorage = (event: StorageEvent) => {
    if (event.key === storageKey(userId)) {
      notify();
    }
  };

  const onCustomChange = (event: Event) => {
    const detail = (event as CustomEvent<DismissedTournamentChange>).detail;
    if (detail?.userId === userId) {
      listener(new Set(detail.tournamentIds));
    }
  };

  window.addEventListener('storage', onStorage);
  window.addEventListener(CHANGE_EVENT, onCustomChange);

  return () => {
    window.removeEventListener('storage', onStorage);
    window.removeEventListener(CHANGE_EVENT, onCustomChange);
  };
}
